import json
from dataclasses import dataclass, field
from typing import List, Optional

@dataclass
class Parent:
    id: int
    name: str
    children: List['Child'] = field(default_factory=list)

@dataclass
class Child:
    id: int
    parent: Optional['Parent'] = None  # BUG: back-pointer creates a cycle

def asdict(obj):
    if hasattr(obj, '__dataclass_fields__'):
        return {k: _coerce(getattr(obj, k)) for k in obj.__dataclass_fields__}
    return obj

def _coerce(v):
    if isinstance(v, list):
        return [_coerce(x) for x in v]
    if hasattr(v, '__dataclass_fields__'):
        return asdict(v)
    return v

def dump_model(obj):
    return json.dumps(asdict(obj), default=str)

if __name__ == '__main__':
    p = Parent(1, 'root')
    c = Child(2, parent=p)
    p.children.append(c)
    print(dump_model(p))
